def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif ratio == 1:
            priorities[i] = 0
        else:
            log_ratio = np.log(1 - ratio)
            if log_ratio == 0:
                priorities[i] = 100
            else:
                priorities[i] = -1 / log_ratio
        if capacity < item * 2:
            priorities[i] *= 1.5
        if i % 2 == 0:
            priorities[i] = priorities[i] ** 0.5
        else:
            priorities[i] = priorities[i] ** 2
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if np.isinf(priorities[i]):
            priorities[i] = max_priority * 2
    return priorities
